import{_ as e,o as a,c as i,d as r}from"./app.c9751d6c.js";const t={},h=r('<h1 id="日记" tabindex="-1"><a class="header-anchor" href="#日记" aria-hidden="true">#</a> 日记</h1><p>正经人谁写日记啊，写日记的也没有正经人。</p><h2 id="_2022-12-20" tabindex="-1"><a class="header-anchor" href="#_2022-12-20" aria-hidden="true">#</a> 2022-12-20</h2><p>今天很开心，很开心，为啥我不说哈哈。</p><h2 id="_2022-12-21" tabindex="-1"><a class="header-anchor" href="#_2022-12-21" aria-hidden="true">#</a> 2022-12-21</h2><p>今天有学校组织的 well-being week 的摸狗活动，好多人我就溜了，我感觉这些做了中央空调的狗子们不会很开心。</p><h2 id="_2022-12-22" tabindex="-1"><a class="header-anchor" href="#_2022-12-22" aria-hidden="true">#</a> 2022-12-22</h2><p>和导师开会，感觉时间还是没控制好太长了，不过也行吧。以后科研要努力的不要天天讲 related work</p><h2 id="_2022-12-23" tabindex="-1"><a class="header-anchor" href="#_2022-12-23" aria-hidden="true">#</a> 2022-12-23</h2><p>今天尝试使用 iCloud-API项目获取 iCloud 的 calendar，在登录就惨遭失败，浪费 3 小时。</p><p>刷了一题力扣，不难贪心就能做。</p><p>表扬 kj 大厨的天竺咖喱鸡肉饭，配合我的迷幻摆盘效果如下图。</p><img src="https://raw.githubusercontent.com/LiuLiujie/liuliujie.github.io/main/images/202212232216776.jpeg" style="zoom:25%;"><p>另收藏一个二喵的红烧牛肉面的菜谱留待以后尝试。</p><img src="https://raw.githubusercontent.com/LiuLiujie/liuliujie.github.io/main/images/202212232242006.png" alt="Screenshot 2022-12-23 at 21.21.42" style="zoom:25%;"><h2 id="_2023-01-05" tabindex="-1"><a class="header-anchor" href="#_2023-01-05" aria-hidden="true">#</a> 2023-01-05</h2><p>新年后的第一篇日记，我曾以为我是一个独行者，但最终发现人始终是一个社交的动物。</p><p>今日话费两小时研究音乐播放器，无果，各种方案列在下面：</p><ul><li>Apple music：太贵，需要拼车，且不支持自导入歌词。奈何apple 生态集成度实在太好，依旧是苹果全家桶的第一选择。</li><li>Spotify: 也不便宜，歌需要自行导入，歌词支持也很一般。</li><li>群辉自搭建：查找音乐太麻烦，歌词支持比较一般。但很便宜就是了。</li></ul>',19),d=[h];function n(c,l){return a(),i("div",null,d)}const o=e(t,[["render",n],["__file","Diary.html.vue"]]);export{o as default};
